        unordered_map<char, int> need, have;
        for (char c : t) need[c]++;
        int required = need.size(), formed = 0;
        int left = 0, minLen = INT_MAX, minStart = 0;

        for (int right = 0; right < s.size(); right++) {
            have[s[right]]++;
            if (need.count(s[right]) && have[s[right]] == need[s[right]])
                formed++;

